import{_ as r,o,c as t,a4 as a}from"./chunks/framework.BIesbIg_.js";const f=JSON.parse('{"title":"Specification","description":"","frontmatter":{},"headers":[],"relativePath":"reference/spec.md","filePath":"reference/spec.md"}'),i={name:"reference/spec.md"};function s(n,e,l,p,c,d){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="specification" tabindex="-1">Specification <a class="header-anchor" href="#specification" aria-label="Permalink to &quot;Specification&quot;">​</a></h1><p>The full GCF specification lives in <a href="https://github.com/blackwell-systems/gcf/blob/main/SPEC.md" target="_blank" rel="noreferrer">SPEC.md</a> at the repository root.</p><p>It covers:</p><ol><li><strong>Grammar</strong> (EBNF, both graph and tabular profiles)</li><li><strong>Header fields</strong> (required and optional, graph profile)</li><li><strong>Node line format</strong> (positional encoding, graph profile)</li><li><strong>Edge line format</strong> (local ID references, graph profile)</li><li><strong>Group headers</strong> (distance-based sections, graph profile)</li><li><strong>Kind abbreviations</strong> (16 standard, extensible) 6a. <strong>Tabular encoding</strong> (generic profile: arrays of objects, nested records, pipe-separated rows)</li><li><strong>Session statefulness</strong> (bare reference protocol)</li><li><strong>Delta encoding extension</strong> (three-outcome protocol)</li><li><strong>Comments</strong></li><li><strong>Token savings analysis</strong> (both graph and tabular profiles)</li><li><strong>Design constraints</strong> (text-only, line-oriented, deterministic, shallow nesting)</li><li><strong>MIME type</strong> (<code>application/vnd.gcf+text</code>)</li><li><strong>Versioning</strong> (GCF, GCF2, GCF3, ...)</li></ol><h2 id="version" tabindex="-1">Version <a class="header-anchor" href="#version" aria-label="Permalink to &quot;Version&quot;">​</a></h2><p>Current: <strong>GCF v1.1</strong> (stable, 2026-06-03)</p><h2 id="profiles" tabindex="-1">Profiles <a class="header-anchor" href="#profiles" aria-label="Permalink to &quot;Profiles&quot;">​</a></h2><p>GCF supports two encoding profiles that share the same grammar primitives (<code>##</code> headers, <code>@</code> IDs, positional fields):</p><ul><li><strong>Graph profile</strong> (Sections 3-6): Encodes code graph payloads (symbols, edges, distance groups) for MCP tool responses.</li><li><strong>Tabular profile</strong> (Section 6a): Encodes arbitrary structured data (arrays of objects, nested records, mixed types) using positional rows and pipe separators.</li></ul><p>Implementations may support one or both profiles.</p><h2 id="stability-guarantee" tabindex="-1">Stability guarantee <a class="header-anchor" href="#stability-guarantee" aria-label="Permalink to &quot;Stability guarantee&quot;">​</a></h2><p>The v1.1 format is stable. Existing payloads will always parse correctly with future decoders. New features (if any) will be additive and backwards-compatible.</p>',12)])])}const h=r(i,[["render",s]]);export{f as __pageData,h as default};
